INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09893e4","title":"Punisher Max: The Platoon","author":"Гарт Эннис,Горан Парлов","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003235442/140/5417/__Punisher_Max_The_Platoon.jpg","isbn":"9781846538933","publisher":"Marvel","pubDate":"2018","language":"Английский","series":"","genres":[],"annotation":"By the time the Punisher was born in Vietnam, Frank Castle had already become a dark legend of the battlefield. Stories about him were told in whispers, if at all. Now the legendary Punisher team of Garth Ennis and Goran Parlov (PUNISHER MAX, FURY MAX) bring the first of those stories to light: the tale of Frank Castle''s first command, and his first kill. COLLECTING: PUNISHER: THE PLATOON 1-6","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":3.5,"review":"","added":9999332,"hdCover":""},{"id":"09893e3","title":"Punisher Max: Girls in White Dresses","author":"Грегг Гервиц,Лоуренс Кэмпбелл","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003193045/140/654b/__Punisher_Max_Girls_in_White_Dresses.jpg","isbn":"978-0785125204","publisher":"Marvel","pubDate":"2009","language":"Английский","series":"","genres":[],"annotation":"In black vans and under cover of night, they descend on the little Mexican town of Tierra Rota, abducting its women and returning them days later like broken dolls. And no one can stop them! That is, until one brave soul approaches Frank Castle with his heart in one hand and a bag full of money in the other.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":3.5,"review":"","added":9999331,"hdCover":""},{"id":"09893e2","title":"Punisher MAX Vol. 10: Valley Forge, Valley Forge","author":"Гарт Эннис,Горан Парлов","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003193044/140/c5bf/__Punisher_MAX_Vol._10_Valley_Forge_Valley_Forge.jpg","isbn":"978-0785127550","publisher":"Marvel","pubDate":"2008","language":"Английский","series":"","genres":[],"annotation":"35 years ago, the Fifth Cavalry disgorged their troops on an isolated Vietnamese hilltop & were met by utter devastation. The final body count ran to well over 700. Standing alone amidst the carnage, a sole survivor: Captain Frank Castle, who years later would be known as the most fearsome vigilante to walk the Earth - the Punisher.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4,"review":"","added":9999330,"hdCover":""},{"id":"09893e1","title":"Punisher MAX, Vol. 9: Long Cold Dark","author":"Гарт Эннис,Горан Парлов","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003193043/140/2612/__Punisher_MAX_Vol._9_Long_Cold_Dark.jpg","isbn":"978-0785128144","publisher":"Marvel","pubDate":"2008","language":"Английский","series":"","genres":[],"annotation":"The Punisher''s wildest foe is back! Left gut-shot in shark-infested waters, Barracuda''s got a major score to settle with Frank Castle. But Barracuda''s no dummy. Charging in with guns blazing is for suckers. He''s got something serious planned. Something that''s going to hit Frank where he hasn''t been hit in years: the black pit that used to be his heart.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4,"review":"","added":9999329,"hdCover":""},{"id":"09893e0","title":"The Punisher, Vol. 8: Widowmaker","author":"Гарт Эннис,Lan Medina","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003192158/140/7dee/__The_Punisher_Vol._8_Widowmaker.jpg","isbn":"978-0785124542","publisher":"Marvel","pubDate":"2007","language":"Английский","series":"","genres":[],"annotation":"Five women, linked by tragedy... and obsession. The Punisher killed their husbands - put them down like dogs - and shattered their lives. Now, they want payback, and they''ve hatched the perfect plan to get it. To bring the wolf to their door, all they need is bait.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4.5,"review":"","added":9999328,"hdCover":""},{"id":"09893df","title":"Punisher MAX Vol. 7: Man of Stone","author":"Гарт Эннис,Леандро Фернандес","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003192157/140/16ef/__Punisher_MAX_Vol._7_Man_of_Stone.jpg","isbn":"978-0785121657","publisher":"Marvel","pubDate":"2007","language":"Английский","series":"","genres":[],"annotation":"The last time General Nikolai Alexandrovich Zakharov encountered Frank Castle, the two men were playing chicken with a dozen nuclear warheads over Moscow. Since then, well, let''s just say Zakharov''s not the type to forgive and forget. When a mutual enemy of Castle comes with the perfect plan to lure Frank out of his hole, Zakharvo is all ears. That man is Rawlins. His bait? His former wife and sometime Castle flame: O''Brien.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4.5,"review":"","added":9999327,"hdCover":""},{"id":"09893de","title":"Justice League: Darkseid War - Power of the Gods","author":"Фрэнсис Манапул","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003160665/140/96a1/Frensis_Manapul__Justice_League_Darkseid_War__Power_of_the_Gods.jpg","isbn":"978-1401261498","publisher":"DC Comics","pubDate":"2016","language":"Английский","series":"","genres":[],"annotation":"From the pages of Geoff Johns’s best-selling storyline in JUSTICE LEAGUE, it’s the Justice League like you’ve never seen them before—with the power of gods!  The greatest evil in the universe has been wiped out. Darkseid, lord of Apokolips, is dead. But the death of a god carries great consequences. Now the Justice League, Earth’s greatest heroes, find themselves with more power than they’ve ever imagined.  But all power has a price—and for the heroes of the Justice League, the price may just be their humanity. Now, Batman is driven non-stop by his power as the God of Knowledge. Superman, the God of Strength, begins to view humans as inferior. The Flash tries to outrun his fate as the God of Death. Green Lantern struggles with his newfound power as the God of Light. Shazam embraces a new pantheon as the God of Gods. And Lex Luthor…  …where Darkseid fell, Lex Luthor may rise to take his place!  If Earth’s greatest heroes can’t find their way back to their humanity, they may bring about their own destruction.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4.5,"review":"","added":9999326,"hdCover":""},{"id":"09893dd","title":"Justice League of America Vol. 2: Survivors of Evil","author":"Мэтт Киндт,Дуг Манке,Эдди Барроуз","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000971576/140/1119/__Justice_League_of_America_Vol._2_Survivors_of_Evil.jpg","isbn":"9781401247263","publisher":"DC Comics","pubDate":"2014","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4,"review":"","added":9999325,"hdCover":""},{"id":"09893dc","title":"Justice League of America Vol. 1: World''s Most Dangerous","author":"Дэвид Финч,Дуг Манке,Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001182576/140/cce9/__Justice_League_of_America_Vol._1_World039s_Most_Dangerous.jpg","isbn":"978-1-4012-4689-1","publisher":"DC Comics","pubDate":"2014","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Following the events of Throne of Atlantis, it is deemed nessesary to create a new Justice League.  This new superhero team is under the command of Col. Steve Travor, of the United States Military''s A.R.G.U.S. division(Advanced Research Group Uniting Superhumans).  Signing up for duty with this new incarnation of the JLA are Catwoman, Katanna, Green Lantern, Green Arrow, Martian Manhunter, Steve Trevor, Hawkman, Star Girl and the long-awaited return of 80s superhero, Vibe.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4,"review":"","added":9999324,"hdCover":""},{"id":"09893db","title":"Punisher MAX Vol. 6: Barracuda","author":"Гарт Эннис,Горан Парлов","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003192156/140/1e8b/__Punisher_MAX_Vol._6_Barracuda.jpg","isbn":"978-0785120230","publisher":"Marvel","pubDate":"2006","language":"Английский","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4.5,"review":"","added":9999323,"hdCover":""},{"id":"09893da","title":"Стражи Галактики. Том 1","author":"Пол Пеллетьер,Уэс Крейг,Дэн Абнетт, Энди Лэннинг ,Брэд Уокер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002323061/140/6daf/__Strazhi_Galaktiki._Tom_1.jpg","isbn":"978-5-9908125-7-4","publisher":"Jellyfish Jam","pubDate":"2017","language":"Русский","series":"Стражи Галактики","genres":["Комиксы","манга","графические романы"],"annotation":"ГАЛАКТИКА В БЕДЕ – ЕЙ НУЖНЫ ГЕРОИ!  И на этот клич, конечно же, отзовутся... ходячее дерево и енот-милитарист?! Откройте для себя комикс легендарных Дэна Абнетта и Энди Леннинга, вдохновивший фильм «Стражи Галактики»! Звездный Лорд собирает новых Стражей Галактики, самых сильных (и самых странных) защитников космоса, которых когда-либо видела наша вселенная! Реактивный Енот, Дракс Разрушитель, Грут, Гамора, Адам Варлок, Мантис, новый Квазар, космическая собака-телепат Космо – все они готовы не просто до последнего биться за спасение нашей галактики, но еще и делать это на стиле! Сейчас их ждет неожиданное вторжение Стражей Галактики из будущего, коварный удар в спину от скруллов во время Секретного Вторжения, а также столкновение с Вселенской Церковью Истины, бадунами и королем Негативной Зоны Бластааром!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4.5,"review":"","added":9999322,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09893d9","title":"Хранители. Начало: Комедиант. Роршах. Красный Корсар (сборник)","author":"Брайан Азарелло,Джон Хиггинс,Лен Уэйн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001547225/140/3ffe/__Hraniteli._Nachalo_Komediant._Rorshah._Krasnyj_Korsar_sbornik.jpg","isbn":"978-5-389-09804-6","publisher":"Азбука, Азбука-Аттикус","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Серия долгожданных приквелов к одному из величайших графических романов всех времен «Хранители».  В течение более чем двадцати лет предыстории культовых персонажей Алана Мура и Дэйва Гиббонса оставались загадкой. До сих пор. Но DC Comics собрал команду самых выдающихся творцов в индустрии, которые смогли развернуть мир «Хранителей», протянув в прошлое истории наиболее противоречивых антигероев из когда-либо действовавших на страницах комиксов. Комедиант, Роршах, Красный Корсар – в первом сборнике издания делюкс.  Победитель премии Айснера и создатель «100 пуль» Брайан Аззарелло привносит свои смелые нюансы в образы Комедианта и Роршаха. Суперзвезда комиксов, художник Ли Бермехо («Джокер», «Лютор», «Бэтмен: Смертельный удар») иллюстрирует погружение во тьму Роршаха, самого опасного из борцов с преступностью.  Джей Джи Джонс («Последний кризис», «Wanted») помещает героя войны в контекст американской истории и мы узнаем, какую роль война во Вьетнаме и убийство Кеннеди сыграли  в судьбе Комедианта.  Лин Уэйн и Джон Хиггинс создали «Проклятие Красного Корсара», захватывающую пиратскую историю, которая рассказывает историю безумия и эпического путешествия по миру запредельных ужасов моряка Гордона Маклахлана.  Эта страшная сказка отсылает к «Истории Черной Шхуны» из «Хранителей», и Джон Хиггинс воплощает безумные видения главного героя с потрясающей реалистичностью и головокружительной глубиной.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":3,"review":"","added":9999321,"hdCover":""},{"id":"09893d8","title":"Город Грехов. Трудное прощание","author":"Фрэнк Миллер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000676384/140/b000/Frenk_Miller__Gorod_Grehov._Trudnoe_proschanie.jpg","isbn":"978-5-367-02822-5","publisher":"Амфора","pubDate":"2013","language":"Русский","series":"Графический роман","genres":["Комиксы","манга","графические романы"],"annotation":"Самый известный цикл Фрэнка Миллера насчитывает семь выпусков и впервые выходит в издательстве «Амфора» на русском языке в полном объеме!  Фрэнк Миллер начинал как художник в сериях популярных комиксов, но настоящую известность получил после того, как стал создавать собственные графические романы. В его работах соединены традиции классического «черного детектива» Хэммета и кровавая эстетика «Бешенных псов» Тарантино, и все это — в поразительном контрасте черного и белого. В первом выпуске, «Трудное прощание», мы знакомимся с громилой Марвом и ныряем вместе с ним на самое дно Города Грехов в поисках убийцы Голди — женщины, которая пахнет, как ангел.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":4.5,"review":"","added":9999320,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09893d7","title":"Каратель. Рождение","author":"Гарт Эннис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003251213/140/f9ac/Gart_Ennis__Karatel._Rozhdenie.jpg","isbn":"","publisher":"Alden","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Шел 1971 год. На фоне растущих потерь и нативоенных настроений американское присутствие во Вьетнаме подходит к концу. Между тем на отрезанной от мира базе огневой поддержки \"Вэлли-Фордж\" на камбоджийской границе капитан Фрэнк Касл остается одним из немногих солдат, упорно сражаются с противником. ЗАпасы истощены, и на базу вот-вот нападут вьетконговцы, грозящие уничтожить весь американский взвод. Какое мрачное решение, которое навсегда изменит его жизнь, каслу предстоит принять, чтобы выжить в бою?  В этом получившем всеобщее признание рассказе суперзвезда Гарт Эннис впервые повествует об ужасах, через которые Каслу пришлось пройти, чтобы вернуться домой из Вьетнама живым, а шокирующий сюжетный поворот навсегда изменит то, каким читатели видят самого известного народного мстителя \"Марвел\".  В сборник вошли \"Рождение\" №1-4 от сценариста Гарта Энниса (\"Каратель\") и художника Дэрика Робинсона (\"Росомаха\").","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":3,"review":"","added":9999319,"hdCover":""},{"id":"09893d6","title":"Человек-паук","author":"Джей Майкл Стражински,Джон Ромита-мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002948978/140/5181/__Chelovekpauk.jpg","isbn":"9772619134100-001","publisher":"Hachette","pubDate":"2019","language":"Русский","series":"Супергерои Marvel. Официальная коллекция.","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Получив с укусом радиоактивного паука невероятные силы, Питер Паркер стал Удивительным Человеком-Пауком. С помощью своих паучьих сил и механических веб-шутеров он охраняет улицы Нью-Йорка от таких опасных злодеев, как Доктор Осьминог, Ящер и Зелёный Гоблин. В этом выпуске вы узнаете историю паутинного героя — с момента его появления до одного из самых заметных современных сюжетов, «С днем рождения».  Внутри: комиксы «Удивительное Фэнтези» №15, «Удивительный Человек-Паук. Ежегодник» №1, «Удивительный Человек-Паук» Том 2 №57-58, №500-502  Дополнительные материалы: история создания Человека-Паука, топ-5 битв Человека-Паука, галерея паучьих костюмов, краткая история персонажа. Плакат.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-05","rating":3.5,"review":"","added":9999318,"hdCover":""},{"id":"09893d5","title":"Росомаха Джейсона Аарона. Омнибус","author":"Джейсон Аарон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005462604/140/92fd/Dzhejson_Aaron__Rosomaha_Dzhejsona_Aarona._Omnibus.jpg","isbn":"978-5-04-109459-1","publisher":"Комильфо","pubDate":"2020","language":"","series":"Росомаха","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-04","rating":3,"review":"","added":9999317,"hdCover":""},{"id":"09893d4","title":"Тор. Викинги","author":"Гленн Фабри,Гарт Эннис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003979032/140/a0de/__Tor._Vikingi.jpg","isbn":"978-5-04-110549-5","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Гарт Эннис, самый скандальный автор комиксов, берётся за могучего Тора! Манхэттен захвачен армией непобедимых викингов-зомби, и Тор плечом к плечу с Доктором Стрэнджем вступит с ними в бой! Норвежскому богу грома и мастеру мистических искусств предстоит отправиться в прошлое, чтобы собрать команду воинов из разных эпох. Но смогут ли женщина-викинг, крестоносец и нацистский лётчик-истребитель справиться с грозной нечистью? В книгу входят комиксы \"Тор. Викинги\" #1–5. Над серией работали Гарт Эннис (\"Каратель\") и Гленн Фабри (обложки \"Проповедник\").","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-04","rating":4,"review":"","added":9999316,"hdCover":""},{"id":"09893d3","title":"Бэтмен. Одержимый Рыцарь (сборник)","author":"Джеф Лоэб","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002888139/140/a758/Dzhef_Loeb__Betmen._Oderzhimyj_Rytsar_sbornik.jpg","isbn":"978-5-389-13949-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2018","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Готовьтесь трепетать от восторга, ведь вас ждут по-настоящему жуткие истории про Темного Рыцаря. Он сражается не только с психами, заполонившими Готэм, но и с призраками своего прошлого – и все это в канун Хэллоуина, одного из самых таинственных и неоднозначных праздников в календаре. Бэтмен привык в одиночку бороться за справедливость, и, несмотря на порой возникающие сомнения, он твердо верит в правильность выбранного пути. Пусть ради этого ему и приходится во многом себе отказывать.  А вот Женщина-Кошка противостоит призракам иного рода. Ей всюду мерещится Бэтмен, пугающий и одновременно столь… притягательный. Кошка сбегает в Рим с целью выяснить правду о своем прошлом, но и там мысли о Бэтмене не оставляют ее. Как и неприятности, без которых по неясной причине не обходится ее итальянское путешествие. Ведь, похоже, Женщину-Кошку из Готэма вытащить можно, а вот Готэм из Рима – никогда...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-04","rating":4,"review":"","added":9999315,"hdCover":""},{"id":"09893d2","title":"Академия Мстителей. Том 1","author":"Кристос Гейдж","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003628727/140/0017/Kristos_Gejdzh__Akademiya_Mstitelej._Tom_1.jpg","isbn":"978-5-04-107584-2","publisher":"Эксмо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"ОНИ СЛЕДУЮЩИЕ МСТИТЕЛИ… ИЛИ СЛЕДУЮЩИЕ ВЛАСТЕЛИНЫ ЗЛА?  Норман Озборн взял шестерых подростков со сверхсилами — Вуаль, Точность, Пыла, Хазмат, Рептилию и Страйкера — и подверг их мучительным тренировкам, пытаясь вылепить нечто по своему подобию. Хэнк Пим и его коллеги — Тигра, Правосудие, Спидбол и Ртуть — спасли их и взяли в свою Академию Мстителей! Их заверили, что они самые многообещающие герои нового поколения, но шокирующая правда в том, что они, возможно, самые опасные из потенциальных угроз во вселенной Marvel! Теперь каждому студенту Академии предстоит решить, вступит он в ряды величайших героев Земли или же станет злодеем завтрашнего дня. Какова будет их реакция после исправительной встречи с Громовержцами и стычки с врагами вроде Капюшона, Таскмастера и Корвака?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-04","rating":4,"review":"","added":9999314,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09893d1","title":"Алая Ведьма. Омнибус: Путь Ведьм. Мир колдовства. Последний заговор","author":"Джеймс Робинсон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002933880/140/6dc8/Dzhejms_Robinson__Alaya_Vedma._Omnibus_Put_Vedm._Mir_koldovstva._Poslednij_zagov.jpg","isbn":"978-5-04-098211-0","publisher":"Fanzon","pubDate":"2019","language":"Русский","series":"Комиксы. Кино","genres":["Комиксы","манга","графические романы"],"annotation":"На улицах Манхэттена, греческих островах и в ирландской глуши Ванде Максимофф предстоит сразиться с чудовищами из древних легенд и узнать правду о своей семье. Расследование приведёт её в Испанию, где Алая Ведьма встретится с призраками инквизиторов. Но ей угрожает нечто большее...  В путешествии по миру волшебства на улицах Парижа Ванда исцелит разбитое сердце героя le Peregrine. А для победы над древним колдуном из Гонконга, Тёмным Тунцзи, объединит силы с юной волшебницей У, которой нужно разобраться в своих чувствах.  Бывшая участница команды \"Мстителей\" смирится с грехами прошлого и встретится со своим братом Пьетро. Но поддержит ли его Ведьма в новой Гражданской войне?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-04","rating":3.5,"review":"","added":9999313,"hdCover":""},{"id":"09893d0","title":"Forever Evil: Rogues Rebellion","author":"Scott Hepburn,Brian Buccellato","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000971864/140/51cd/__Forever_Evil_Rogues_Rebellion.jpg","isbn":"9781401249410","publisher":"DC Comics","pubDate":"2014","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"A tie-in to the crossover event FOREVER EVIL! The Rogues--the Flash''s gallery of villains--call no man boss, but a new evil threat might not leave them much choice! Will they fall in line, or refuse and risk certain death? Will the Rogues be able to take on the Crime Syndicate together?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-04","rating":4,"review":"","added":9999312,"hdCover":""},{"id":"09893cf","title":"Forever Evil: Arkham War","author":"Peter J. Tomasi","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000971594/140/d3d6/Peter_J._Tomasi__Forever_Evil_Arkham_War.jpg","isbn":"9781401249403","publisher":"DC Comics","pubDate":"2014","language":"Английский","series":"Forever Evil","genres":["Комиксы","манга","графические романы"],"annotation":"Madness and mayhem hit the streets as both Arkham Asylum and Blackgate Prison unleash their prisoners upon the helpless citizens of Gotham. And with no Dark Knight to protect the city, what horrors will follow?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-04","rating":4,"review":"","added":9999311,"hdCover":""},{"id":"09893ce","title":"Forever Evil: Blight","author":"J. M. DeMatteis,Ray Fawkes,Mikel Janin","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000971858/140/a0d3/__Forever_Evil_Blight.jpg","isbn":"9781401250065","publisher":"DC Comics","pubDate":"2014","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Spinning out of the events of the massive crossover event FOREVER EVIL, comes FOREVER EVIL: BLIGHT! After a battle between the three Justice Leagues, the heroes of the DC Universe--including Superman, Batman and Wonder Woman--have all gone missing. With unspeakable evil called Blight unleashed on the world, it''s up to the Justice League Dark, Swamp Thing, Pandora and the Phantom Stranger to try and stop them from destroying everything around them.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-04","rating":3,"review":"","added":9999310,"hdCover":""},{"id":"09893cd","title":"Forever Evil: A.R.G.U.S.","author":"Philip Tan,Sterling Gates","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000971866/140/c81d/__Forever_Evil_A.R.G.U.S..jpg","isbn":"9781401249397","publisher":"DC Comics","pubDate":"2014","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-04","rating":3.5,"review":"","added":9999309,"hdCover":""},{"id":"09893cc","title":"Punisher MAX Vol. 5: The Slavers","author":"Гарт Эннис,Леандро Фернандес","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003192155/140/1ed2/__Punisher_MAX_Vol._5_The_Slavers.jpg","isbn":"978-0785118992","publisher":"Marvel","pubDate":"2006","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"On a pitch-black Brooklyn night, in a dead-end alley, Frank Castle brutally dispatches a crew of Albanian thugs menacing a young woman. Her name is Viorica, she''s from Moldavia, and when she tells Frank her story, that''s when the real killing starts!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-04","rating":4.5,"review":"","added":9999308,"hdCover":""},{"id":"09893cb","title":"Punisher Max Vol. 4: Up is Down and Black is White","author":"Гарт Эннис,Леандро Фернандес","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003192154/140/ea05/__Punisher_Max_Vol._4_Up_is_Down_and_Black_is_White.jpg","isbn":"978-0785117315","publisher":"Marvel","pubDate":"2006","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Uber-gangster Nicky Cavella is back with a vengeance - this time hitting Frank Castle where he least expects it - right in the black pit of his hardened heart. With an unspeakable act, Nicky will go right to the top of Frank''s \"to-do\" list - and there''s nowhere he''d rather be.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-04","rating":4,"review":"","added":9999307,"hdCover":""},{"id":"09893ca","title":"Punisher MAX Vol. 3: Mother Russia","author":"Гарт Эннис,Дуг Брейтуэйт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003192152/140/11d6/__Punisher_MAX_Vol._3_Mother_Russia.jpg","isbn":"978-0785116035","publisher":"Marvel","pubDate":"2006","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Nick Fury''s got a job that needs doing - in Russia. The kind of suicide mission any sane man wouldn''t ponder for a second. And that''s exactly why he needs the Punisher. Searching for a deadly retrovirus whose sale on the black market could bring the world to its knees, Frank Castle penetrates a Russian nuclear silo...and comes face-to-face with the Mongolian!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-04","rating":4,"review":"","added":9999306,"hdCover":""},{"id":"09893c9","title":"Каратель. Том 2. Ирландская кухня","author":"Гарт Эннис,Леандро Фернандес","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001796450/140/3725/__Karatel._Tom_2._Irlandskaya_kuhnya.jpg","isbn":"978-9859039324","publisher":"ALDEN comics","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Один из самых противоречивых авторов комиксов направляет одного из самых противоречивых персонажей по новому пути – и маршрут выбирает только он сам!  В пабе Ирландской кухни взрывается бомба, и Фрэнк Касл берётся за смертельное задание, которое толкает его в гущу распри между двумя бандами. Ясно одно: Каратель ни с кем церемониться не будет!  В сборник вошли «Каратель» №7-12 от сценариста ГАРТА ЭННИСА («Проповедник») и художника ЛЕАНДРО ФЕРНАНДЕСА («Росомаха»).  18+","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-04","rating":3.5,"review":"","added":9999305,"hdCover":""},{"id":"09893c8","title":"Каратель. Том 1. В начале","author":"Гарт Эннис,Том Палмер,Льюис Лароза","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001553715/140/e00d/__Karatel._Tom_1._V_nachale.jpg","isbn":"978-985-90341-9-0","publisher":"ALDEN comics","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Давний напарник Карателя по имени Микрочип вернулся, и теперь охотник сам становится добычей. Но сперва Микро предлагает Фрэнку Каслу сделку, от которой тому не стоит отказываться. Приготовьтесь к свисту пуль, кровавой бойне и резким поворотам сюжета - здесь все будет по-взрослому!  Первый комикс о Карателе, изданный на русском языке. Серия Punisher MAX от знаменитого сценариста Гарта Энниса (Preacher). 18+","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-04","rating":4.5,"review":"","added":9999304,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09893c7","title":"Marvel 1985","author":"Марк Миллар,Томми Ли Эдвардс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003547998/140/5698/__Marvel_1985.jpg","isbn":"978-5-04-108432-5","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"ВСЕЛЕННАЯ MARVEL ОЖИЛА! В этой всеми ожидаемой истории Марк Миллар и Томми Ли Эдвардс перенесут вас в странный и экзотический мир: в 1985 год. Там юный Тоби Гудмен живёт обычной жизнью, читая комиксы Marvel, чтобы сбежать от проблем в отношениях с матерью и отчимом и сильнее сблизиться с ленивым, но добрым отцом. И кажется, что это будет продолжаться до скончания веков, как вдруг Тоби натыкается на старый дом, заселённый злодеями, что терроризировали вселенную Marvel. Поначалу никто не верит его словам, однако затем начинают появляться жертвы. Злодеи Marvel кажутся забавными и прикольными, когда ты читаешь комиксы про них, но что вы сделаете, если перед вами предстанут Доктор Дум, Человек-Крот или его кротоиды? Когда самые опасные злодеи, что появлялись на страницах комиксов, вдруг нападут на наш мир, исполняя таинственный и зловещий план, целый город будет повергнут в хаос и беспорядок. Тоби хочет понять, как и почему суперзлодеи перенеслись из воображения в реальность, но сначала ему нужно пережить их атаки.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-04","rating":4,"review":"","added":9999303,"hdCover":""},{"id":"09893c6","title":"Болотная Тварь. Время Святых","author":"Kelley Jones,Лен Уэйн,Джейсон Фабок,Том Кинг","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003630558/140/2d16/__Bolotnaya_Tvar._Vremya_Svyatyh.jpg","isbn":"978-5-389-17615-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Алек Холланд, он же Болотная Тварь, стал защитником Зелени – силы, связующей всю растительную жизнь на Земле. Он черпает в ней мощь, позволяющую ему играючи сокрушать здания и бросать вызов самым грозным противникам. Но что, если Алек очутится посреди ледяной бури, лишившись связи с Зеленью? Что если с ним не будет никого, кроме ребенка, который может положиться только на это странное существо? Что если по пятам будет идти кровожадное чудовище, которое с каждым шагом будет лишь крепнуть, а Алек – слабеть?  Получится ли у героев выжить, и на что похоже путешествие по ледяной пустыне бок о бок с Болотной Тварью, вы узнаете из невероятно красивой и проникновенной истории, которую вполне можно считать первым шажком к чему-то более грандиозному…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-04","rating":4.5,"review":"","added":9999302,"hdCover":""},{"id":"09893c5","title":"Блэксэд. Книга 1. Где-то среди теней. Полярная нация (сборник)","author":"Хуан Диаc Каналес, Хуанхо Гуарнидо","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001439265/140/f4b8/Huan_Diac_Kanales_Huanho_Guarnido__Bleksed._Kniga_1._Gdeto_sredi_tenej._Polyarna.jpg","isbn":"978-5-389-09844-2","publisher":"Азбука","pubDate":"2015","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы","Фантастика"],"annotation":"В первый омнибус вошли два первых тома серии «Блэксэд»: «Где-то среди теней» и «Полярная нация».  Роскошная графика и богатый кинематографический стиль Хуанхо Гуарнидо в сочетании с писательским мастерством Хуана Диаcа Каналеса, чьи сценарии критика сравнивает с романами Дэшила Хэммета и Рэймонда Чандлера, обеспечили серии «Блэксэд» всемирную славу и с десяток престижных наград, включая приз Ангулемского комик-кона за лучшее художественное произведение, и не говоря уже о трехкратной номинации на премию Айснера.  Итак, если утро начинается с остывшего трупа первой любви и это не метафора… Следует признать, что жизнь частного детектива Джона Блэксэда далека от пасторальной идиллии. Что неудивительно для кота его профессии в американском мегаполисе, разъеденном коррупцией сверху донизу. Джон постоянно рискует жизнью и ходит по краю, что не мешает ему крутить романы с опасными женщинами и распутывать интриги сильных мира сего…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-03","rating":4.5,"review":"","added":9999301,"hdCover":""},{"id":"09893c4","title":"Бэтмен. Смерть семьи. Эндшпиль (сборник)","author":"Скотт Снайдер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003626885/140/1525/Skott_Snajder__Betmen._Smert_semi._Endshpil_sbornik.jpg","isbn":"978-5-389-17614-0","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Готэм-сити целый год дышал свободно и забыл о страхе, который наводил на обитателей мегаполиса безумец с вечной улыбкой на лице. После того, как Джокер в прямом смысле слова потерял лицо, он исчез с готэмских улиц. Город спит спокойно, но не до сна Бэтмену и его союзникам. Они знают, что Джокер всегда возвращается. И в этот раз он вернётся за своим. За своим лицом и в свой город…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-03","rating":3.5,"review":"","added":9999300,"hdCover":""},{"id":"09893c3","title":"Бэтмен. Нулевой год (сборник)","author":"Скотт Снайдер,Грег Капулло","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003326302/140/85ce/__Betmen._Nulevoj_god_sbornik.jpg","isbn":"978-5-389-17286-9","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"До наступления эры супергероев, до того как Бэтмен простер свои крылья над Готэмом, защищая невинных и карая злодеев, наследник влиятельной и богатой семьи, владелец могучей промышленной империи, Брюс Уэйн исчезает на несколько лет. Покров тьмы и тайны – это именно то, что было необходимо Брюсу, чтобы обрести себя. Скрывая свое возвращение, свое прошлое и свое лицо, он выходит на улицы Готэма и начинает долгий путь борца с преступностью.  Творческая команда Скотта Снайдера, Грега Капулло и Дэнни Мики с гордостью представляет новый взгляд на личность Темного Рыцаря и захватывающую сагу об осажденном городе в новом издании «Бэтмен. Нулевой год».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-03","rating":4,"review":"","added":9999299,"hdCover":""},{"id":"09893c2","title":"Сорвиголова: Страх","author":"Джеф Лоэб,Тим Сейл","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003272134/140/561b/__Sorvigolova_Strah.jpg","isbn":"978-5-6040123-9-0","publisher":"Параллель Комикс","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"«Сорвиголова: Страх» — смесь виртуозного экшена и душераздирающей драмы, которая стала жемчужиной комиксов Marvel.  Легендарный дуэт Джефа Лоэба и Тима Сейла рассказал в «Страхе» историю о хрупких чувствах того, кого привыкли считать неуязвимым. историю про супергероя, в которой каждый может найти самого себя.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-03","rating":4.5,"review":"","added":9999298,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09893c1","title":"Космический Призрачный Гонщик. Малыш Танос должен умереть","author":"Донни Кейтс,Дилан Бернетт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003035049/140/3512/__Kosmicheskij_Prizrachnyj_Gonschik._Malysh_Tanos_dolzhen_umeret.jpg","isbn":"978-5-04-105005-4","publisher":"Эксмо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"ФРЭНК КАСЛ ЗАКЛЮЧИЛ СДЕЛКУ С ДЬЯВОЛОМ И ТОТ СДЕЛАЛ ЕГО ПРИЗРАЧНЫМ ГОНЩИКОМ. После договора с Галактусом он стал Космическим. А служба Таносу сделала его... трупом?! Не переживайте, Касла не так просто убить. Он вернулся... и придумал, как сделать вселенную лучше! Всё началось с идеи, столь простой, что диву даёшься, как никто этого до тебя не придумал. Но, как и любое достойное дело, провернуть это будет нелегко. Касл сразится с космическими акулами, раскидает Стражей Галактики будущего и наткнётся на Галактуса во время драки в баре! А, и не забудьте про... младенца Таноса?! Это Фрэнк... эм... Кара... эм... Космический Призрачный Гонщик — самый безумный герой, которого видывал свет! В СБОРНИК ВОШЛИ КОМИКСЫ \"КОСМИЧЕСКИЙ ПРИЗРАЧНЫЙ ГОНЩИК\" #1–5, НАПИСАННЫЕ ДОННИ КЕЙТСОМ И НАРИСОВАННЫЕ ДИЛАНОМ БЁРНЕТТОМ.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-03","rating":3.5,"review":"","added":9999297,"hdCover":""},{"id":"09893c0","title":"Капитан Америка. Красная Угроза. Полное издание","author":"Эд Брубейкер,Стив Эптинг,Хавьер Пулидо,Майк Перкинс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001629446/140/e100/__Kapitan_Amerika._Krasnaya_Ugroza._Polnoe_izdanie.jpg","isbn":"978-5-91878-157-9","publisher":"Фантастика Книжный Клуб","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Полгода назад Кроссбоунс похитил дочь Красного Черепа из правительственного исправительного лагеря и залёг на дно. Теперь он и это злосчастное отродье прибыли на юго-восток США, чтобы атаковать АИМ, однако никто не ждал появления Капитана Америка и ЩИТа. Ошибка Агента 13 превращает всё в настоящую катастрофу! В поисках бывшего напарника Кэп пересекает Атлантику — так начинается история, в которой он будет сражаться плечом к плечу со старыми товарищами. Но не только Кэп и Зимний Солдат решили побывать за границей. Кроссбоунс и Син, движимые местью, оказываются там же! Остаётся выяснить, как именно новый враг Кэпа — генерал Александр Лукин, глава одной из самых могущественных корпораций мира, — связан с Красным Черепом. В качестве бонуса: ранее неизвестный эпизод времен Второй мировой войны, в которой Кэп, Баки и сержант Фьюри вместе с его Ревунами проводят операцию в немецком тылу, пытаясь не дать Красному Черепу совершить невиданное по своей чудовищности нападение на войска союзников!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2020-03","rating":4,"review":"","added":9999296,"hdCover":""}]');
